import { icons as LucideIcons } from 'lucide-react';

const kebabToPascal = (kebab: string) =>
  kebab
    .split('-')
    .map(word => word.charAt(0).toUpperCase() + word.slice(1))
    .join('');

/**
 * IconRenderer renders a selected icon by name from iconsData.
 * @param {Object} props
 * @param {string} props.name - The name of the icon to render.
 * @param {string} [props.className] - Additional class names for styling.
 */
export function IconRenderer({ name, className = '' }: { name: string; className?: string }) {
  if (!name) return null;
  const Icon = (LucideIcons as any)[kebabToPascal(name)];
  if (!Icon) return null;
  return <Icon className={className} aria-label={name} />;
}
