import { useState } from 'react';
import * as LucideIcons from 'lucide-react';
import { iconsData } from '../../icons-data';
import '../../src/styles/tailwind.css';
import { Popover } from './ui/popover';
import { Input } from './ui/input';
import { Button } from './ui/button';
import { ColorPicker } from './ColorPicker';

const kebabToPascal = (kebab: string) =>
  kebab
    .split('-')
    .map(word => word.charAt(0).toUpperCase() + word.slice(1))
    .join('');

function filterIcons(icons: typeof iconsData, search: string) {
  if (!search) return icons;
  const s = search.toLowerCase();
  return icons.filter(icon =>
    icon.name.toLowerCase().includes(s) ||
    icon.categories.some(cat => cat.toLowerCase().includes(s)) ||
    icon.tags.some(tag => tag.toLowerCase().includes(s))
  );
}

/**
 * IconPicker component allows users to select an icon from the provided iconsData.
 * @param {Object} props
 * @param {function} props.onSelect - Callback when an icon is selected or color is changed.
 * @param {object} [props.value] - Currently selected icon config: { name, color }.
 * @param {boolean} [props.colorPicker] - If true, enables color picking for the icon.
 */
export type IconPickerSize = 'small' | 'medium' | 'large';

interface IconConfig {
  name: string;
  color?: string;
}

interface IconPickerProps {
  onSelect: (config: IconConfig) => void;
  value?: IconConfig;
  size?: IconPickerSize;
  triggerType?: 'text' | 'icon';
  triggerText?: string;
  clearable?: boolean;
  colorPicker?: boolean;
}

const sizeConfig = {
  small: {
    button: 'h-9 w-9 px-2 py-1 text-xs',
    icon: 'w-4 h-4',
    grid: 'gap-2',
    popover: 'w-64',
    header: 'px-2 py-2',
    search: 'py-1 px-2 text-xs',
    trigger: 'h-9 px-2 text-xs',
    triggerIcon: 'w-4 h-4',
  },
  medium: {
    button: 'h-12 w-12 p-2 text-base',
    icon: 'w-6 h-6',
    grid: 'gap-3',
    popover: 'w-96',
    header: 'px-4 py-3',
    search: 'py-2 px-3 text-sm',
    trigger: 'h-12 px-4 text-base',
    triggerIcon: 'w-5 h-5',
  },
  large: {
    button: 'h-16 w-16 p-3 text-lg',
    icon: 'w-9 h-9',
    grid: 'gap-4',
    popover: 'w-[32rem]',
    header: 'px-6 py-4',
    search: 'py-3 px-4 text-lg',
    trigger: 'h-16 px-6 text-lg',
    triggerIcon: 'w-8 h-8',
  },
};

export function IconPicker({ onSelect, value = { name: '', color: '#000000' }, size = 'medium', triggerType = 'icon', triggerText = 'Choose Icon', clearable = true, colorPicker = false }: IconPickerProps) {
  const [open, setOpen] = useState(false);
  const [search, setSearch] = useState('');
  const [hoveredIcon, setHoveredIcon] = useState<string | null>(null);
  const filteredIcons = filterIcons(iconsData, search);
  // Use value directly
  const selected = value;
  const SelectedIcon = selected?.name ? (LucideIcons as any)[kebabToPascal(selected.name)] : (() => <span className="w-5 h-5" />);
  const iconColor = selected?.color || '#000000';

  const clearSearch = () => setSearch('');
  const config = sizeConfig[size];

  return (
    <>
      <style>{`
        @keyframes slideDown {
          from {
            opacity: 0;
            transform: translateY(-12px) scale(0.95);
          }
          to {
            opacity: 1;
            transform: translateY(0) scale(1);
          }
        }
        
        @keyframes iconScale {
          0% { transform: scale(1); }
          50% { transform: scale(1.15); }
          100% { transform: scale(1); }
        }
        
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.7; }
        }
        
        @keyframes shimmer {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(100%); }
        }
        
        .animate-slide-down {
          animation: slideDown 0.25s cubic-bezier(0.16, 1, 0.3, 1);
        }
        
        .animate-icon-scale {
          animation: iconScale 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
        }
        
        .animate-pulse-soft {
          animation: pulse 2s cubic-bezier(0.4, 0, 0.6, 1) infinite;
        }
        
        .glass-morphism {
          background: rgba(255, 255, 255, 0.9);
          backdrop-filter: blur(20px);
          border: 1px solid rgba(255, 255, 255, 0.3);
        }
        
        .icon-glow {
          box-shadow: 0 0 25px rgba(99, 102, 241, 0.4), 0 0 50px rgba(147, 51, 234, 0.2);
        }
        
        .search-glow {
          box-shadow: 0 0 20px rgba(99, 102, 241, 0.2);
        }
        
        .shimmer-effect {
          position: relative;
          overflow: hidden;
        }
        
        .shimmer-effect::before {
          content: '';
          position: absolute;
          top: 0;
          left: -100%;
          width: 100%;
          height: 100%;
          background: linear-gradient(90deg, transparent, rgba(255,255,255,0.6), transparent);
          animation: shimmer 2s infinite;
          z-index: 1;
        }
        
        .gradient-border {
          background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
          padding: 2px;
          border-radius: 12px;
        }
        
        .gradient-border-inner {
          background: white;
          border-radius: 10px;
        }
      `}</style>

      <Popover open={open} onOpenChange={setOpen}>
        <Popover.Trigger asChild>
          <Button 
            type="button" 
            aria-label="Pick an icon"
            className={`
              group relative flex items-center gap-3 border-2 rounded-xl transition-colors duration-200
              ${config.trigger}
              ${value?.name 
                ? 'border-indigo-400 bg-gradient-to-br from-indigo-50 to-purple-50 shadow-md shadow-indigo-500/10' 
                : 'border-gray-200 bg-white hover:border-indigo-300'
              }
              ${triggerType === 'icon' ? 'justify-center w-auto min-w-0 px-2' : ''}
              ${triggerType === 'text' ? 'min-w-0 w-auto max-w-full' : ''}
            `}
            style={triggerType === 'icon'
              ? { minWidth: 0, width: 'auto', outline: 'none', boxShadow: 'none' }
              : triggerType === 'text' && (triggerText?.trim() === '' || !triggerText)
              ? { minWidth: 120, outline: 'none', boxShadow: 'none' }
              : triggerType === 'text' && triggerText?.trim().length < 8
              ? { minWidth: 80, outline: 'none', boxShadow: 'none' }
              : { outline: 'none', boxShadow: 'none' }}
          >
            <div className="relative">
              {value?.name ? (
                <div className="relative">
                  <SelectedIcon className={`${config.triggerIcon} text-indigo-600 group-hover:scale-110 transition-transform duration-200`} style={{ color: iconColor }} />
                  <div className="absolute inset-0 bg-indigo-400 rounded-full blur-lg opacity-20 group-hover:opacity-40 transition-opacity"></div>
                </div>
              ) : (
                <div className={`border-2 border-dashed border-gray-300 rounded-lg flex items-center justify-center group-hover:border-indigo-400 transition-all duration-200 shimmer-effect ${config.triggerIcon}`}>
                  <div className="w-2 h-2 bg-gray-300 rounded-full group-hover:bg-indigo-400 animate-pulse-soft"></div>
                </div>
              )}
            </div>
            {triggerType === 'text' && (
              <span className="font-medium flex-1 text-left text-gray-700 group-hover:text-indigo-700 transition-colors duration-200">
                {(triggerText?.trim() || 'Choose Icon')}
              </span>
            )}
            <svg 
              className={`w-4 h-4 text-gray-400 group-hover:text-indigo-500 transition-all duration-300 ${open ? 'rotate-180 text-indigo-500' : ''}`} 
              fill="none" 
              stroke="currentColor" 
              viewBox="0 0 24 24"
            >
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
            </svg>
          </Button>
        </Popover.Trigger>
        
        <Popover.Content className={`${config.popover} p-0 border shadow-lg rounded-xl animate-slide-down`}>
          <div className="bg-white rounded-xl overflow-hidden border border-gray-200">
            {/* Header */}
            <div className={`${config.header} bg-gray-50 border-b border-gray-200 flex items-center justify-between gap-1 min-h-0`}>
              <div className="flex items-center gap-2 min-h-0">
                <div className="w-5 h-5 bg-indigo-500 rounded flex items-center justify-center">
                  <svg className="w-3 h-3 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 2.143L13 21l-2.286-6.857L5 12l5.714-2.143L13 3z" />
                  </svg>
                </div>
                <div className="leading-tight">
                  <h3 className="text-xs font-semibold text-gray-800">Select Icon</h3>
                  <p className="text-[10px] text-gray-500 leading-none">{filteredIcons.length} icons</p>
                </div>
              </div>
              <Popover.Close asChild>
                <Button 
                  className="w-6 h-6 min-w-0 flex items-center justify-center rounded-full bg-gray-200 hover:bg-gray-300 text-gray-700 ml-2 p-0 leading-none"
                  aria-label="Close" 
                  type="button"
                  style={{ width: 20, height: 20, minWidth: 0, padding: 0, lineHeight: 1 }}
                >
                  <svg className="w-3 h-3 block" fill="none" stroke="currentColor" strokeWidth="2.2" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </Button>
              </Popover.Close>
            </div>
            {/* Search + Color Picker Row */}
            <div className="px-3 py-2 bg-white border-b border-gray-100 flex items-center">
              <div className="relative flex-grow min-w-0">
                <div className="absolute left-2.5 top-1/2 -translate-y-1/2">
                  <svg className="w-4 h-4 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                  </svg>
                </div>
                <Input
                  placeholder="Search icons..."
                  value={search}
                  onChange={e => setSearch(e.target.value)}
                  autoFocus
                  className={`pl-9 pr-8 border border-gray-200 rounded-lg ${config.search}`}
                  style={{ boxShadow: 'none', outline: 'none', width: '100%' }}
                />
                {search && (
                  <button
                    onClick={clearSearch}
                    className="absolute right-2.5 top-1/2 -translate-y-1/2 p-0.5 rounded hover:bg-gray-100"
                  >
                    <svg className="w-3 h-3 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                    </svg>
                  </button>
                )}
              </div>
              {/* Inline Color Picker trigger (only if colorPicker and icon selected) */}
              {colorPicker && selected?.name && (
                <div className="flex-shrink-0 flex items-center justify-end pl-3">
                  <ColorPicker
                    item={selected.name}
                    data={{ [selected.name]: iconColor }}
                    onChange={(_item, color) => onSelect({ name: selected.name, color })}
                    size={size === 'small' ? 'small' : size === 'large' ? 'large' : 'medium'}
                    showValue={false}
                  />
                </div>
              )}
            </div>

            {/* Icons Grid */}
            <div className="h-80 overflow-y-auto px-4 pb-4">
              {filteredIcons.length > 0 ? (
                <div className={`grid grid-cols-6 ${config.grid} py-2`}>
                  {filteredIcons.slice(0, 36).map((icon, index) => {
                    const Icon = (LucideIcons as any)[kebabToPascal(icon.name)];
                    if (!Icon) return null;
                    const isSelected = selected.name === icon.name;
                    const isHovered = hoveredIcon === icon.name;
                    // All icons use the current color if colorPicker is enabled and a color is set
                    const iconStyle = colorPicker && selected.color ? { color: selected.color } : {};
                    return (
                      <div key={icon.name} className="relative">
                        <Button
                          className={`
                            group relative flex items-center justify-center
                            rounded-lg border transition-all duration-200 min-w-0
                            ${config.button}
                            ${isSelected 
                              ? 'border-indigo-500 bg-indigo-50 shadow-md' 
                              : 'border-gray-200 bg-white hover:border-indigo-300 hover:bg-indigo-50 hover:shadow-sm'
                            }
                          `}
                          style={{ minWidth: 0, boxSizing: 'border-box', boxShadow: 'none', outline: 'none' }}
                          onClick={() => {
                            onSelect({ name: icon.name, color: selected.color || '#000000' });
                            setOpen(false);
                          }}
                          onMouseEnter={() => setHoveredIcon(icon.name)}
                          onMouseLeave={() => setHoveredIcon(null)}
                          type="button"
                          aria-label={icon.name}
                          title={icon.name}
                        >
                          <Icon 
                            className={`transition-colors duration-200 flex-shrink-0 ${config.icon} ${isSelected ? 'text-indigo-600' : 'text-gray-700 group-hover:text-indigo-600'}`}
                            strokeWidth={1.5}
                            style={iconStyle}
                          />
                          {/* Clean selection indicator or clear button */}
                          {isSelected && clearable ? (
                            <button
                              type="button"
                              aria-label="Clear selected icon"
                              className="absolute -top-1 -right-1 w-4 h-4 bg-white rounded-full border border-gray-300 flex items-center justify-center shadow-sm hover:bg-gray-100 focus:outline-none"
                              style={{ zIndex: 2 }}
                              onClick={e => {
                                e.stopPropagation();
                                onSelect({ name: '', color: '#000000' });
                              }}
                            >
                              <svg className="w-2.5 h-2.5 text-gray-500" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                              </svg>
                            </button>
                          ) : isSelected ? (
                            <div className="absolute -top-1 -right-1 w-3 h-3 bg-indigo-500 rounded-full border-2 border-white"></div>
                          ) : null}
                        </Button>
                        {/* Simplified tooltip */}
                        {isHovered && (
                          <div className="absolute -top-8 left-1/2 -translate-x-1/2 z-30 pointer-events-none">
                            <div className="bg-gray-800 text-white text-xs px-2 py-1 rounded whitespace-nowrap">
                              {icon.name}
                            </div>
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center h-64 text-center px-4">
                  <div className="w-12 h-12 bg-gray-100 rounded-lg flex items-center justify-center mb-3">
                    <svg className="w-6 h-6 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                    </svg>
                  </div>
                  <h4 className="text-sm font-semibold text-gray-600 mb-1">No icons found</h4>
                  <p className="text-xs text-gray-500 mb-3">
                    Try adjusting your search terms
                  </p>
                  {search && (
                    <Button
                      onClick={clearSearch}
                      className="px-3 py-1.5 text-xs bg-gray-100 text-gray-600 hover:bg-gray-200 rounded-md"
                    >
                      Clear search
                    </Button>
                  )}
                </div>
              )}
            </div>
          </div>
        </Popover.Content>
      </Popover>
    </>
  );
}