import * as React from 'react';
import * as RadixPopover from '@radix-ui/react-popover';
import { cn } from './utils';

interface PopoverProps {
  open?: boolean;
  onOpenChange?: (open: boolean) => void;
  children: React.ReactNode;
}

export function Popover({ open, onOpenChange, children }: PopoverProps) {
  return (
    <RadixPopover.Root open={open} onOpenChange={onOpenChange}>
      {children}
    </RadixPopover.Root>
  );
}

Popover.Trigger = RadixPopover.Trigger;

interface PopoverContentProps extends React.ComponentPropsWithoutRef<typeof RadixPopover.Content> {
  className?: string;
}

Popover.Content = function PopoverContent({ className, ...props }: PopoverContentProps) {
  return (
    <RadixPopover.Portal>
      <RadixPopover.Content
        align="start"
        sideOffset={8}
        className={cn(
          "z-50 w-[320px] rounded-lg border bg-popover p-0 shadow-xl focus:outline-none animate-in fade-in-0 slide-in-from-top-2",
          className
        )}
        {...props}
      />
    </RadixPopover.Portal>
  );
};
Popover.Close = RadixPopover.Close;
