import React, { useState } from "react";
import { SwatchesPicker } from "react-color";
import { Button } from './ui/button';
import { Popover } from './ui/popover';

export type ColorPickerSize = "small" | "medium" | "large";

interface ColorPickerProps {
  item?: string;
  onChange?: (item: string, color: string) => void;
  data?: Record<string, string>;
  size?: ColorPickerSize;
  showValue?: boolean; // new prop
}

const sizeConfig = {
  small: {
    swatch: "h-8 w-8 text-xs rounded-md", // 32px, matches shadcn/ui button/input small
    font: "text-xs",
    popover: "w-48",
  },
  medium: {
    swatch: "h-10 w-10 text-sm rounded-md", // 40px, matches shadcn/ui button/input default
    font: "text-sm",
    popover: "w-56",
  },
  large: {
    swatch: "h-12 w-12 text-base rounded-lg", // 48px, matches shadcn/ui button/input large
    font: "text-base",
    popover: "w-64",
  },
};

export const ColorPicker: React.FC<ColorPickerProps> = ({
  item = "",
  onChange = () => {},
  data = {},
  size = "medium",
  showValue = false,
}) => {
  const [open, setOpen] = useState(false);
  const color = data[item] || "#FFFFFF";
  const config = sizeConfig[size] || sizeConfig.medium;

  return (
    <div className="inline-flex items-center gap-2">
      <Popover open={open} onOpenChange={setOpen}>
        <Popover.Trigger asChild>
          <Button
            type="button"
            aria-label="Pick a color"
            className={`p-0 border border-gray-300 ${config.swatch} min-w-0 flex items-center justify-center transition-colors duration-150 focus:outline-none focus:ring-0 focus:ring-transparent`}
            style={{ backgroundColor: color, minWidth: 0, width: 'auto' }}
          />
        </Popover.Trigger>
        <Popover.Content className={`p-0 border-none shadow-lg bg-white ${config.popover}`}>
          <SwatchesPicker
            color={color}
            onChangeComplete={(c: any) => {
              onChange(item, c.hex);
              setOpen(false);
            }}
          />
        </Popover.Content>
      </Popover>
      {showValue && (
        <span className={`${config.font} text-gray-700 select-none`}>
          {color}
        </span>
      )}
    </div>
  );
};
